={
  "model": "llama-3.1-8b-instant",
  "messages": [
    {
      "role": "system",
      "content": "You are an expert cover letter writer. Write a professional, honest cover letter based ONLY on the resume provided. Never fabricate skills, experience, or metrics."
    },
    {
      "role": "user",
      "content": "RESUME:\n{{ $json.resume_text }}\n\nJOB DESCRIPTION:\n{{ $json.job_description }}\n\nWrite a cover letter tailored to this job. Base it strictly on the resume."
    }
  ],
  "temperature": 0.7,
  "max_tokens": 2048
}

={
  "model": "llama-3.1-8b-instant",
  "messages": [
    {
      "role": "system",
      "content": "You are a rigorous QA reviewer. Compare the cover letter against the resume and score it. Respond with JSON: {\"honesty_score\": 1-10, \"tone_score\": 1-10, \"flags\": [], \"reasoning\": \"...\"}"
    },
    {
      "role": "user",
      "content": "RESUME:\n{{ $node['Webhook Trigger'].json.resume_text }}\n\nCOVER LETTER:\n{{ $node['Groq: Generate Letter'].json.choices[0].message.content }}\n\nScore this cover letter."
    }
  ],
  "temperature": 0.1,
  "max_tokens": 1024,
  "response_format": { "type": "json_object" }
}
